<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('orders.view');$pageTitle='Orders';require VP3_ROOT.'/includes/admin-header.php';$cid=(int)vp3_input('customer_id');$sql='SELECT o.*,c.name customer_name,c.email FROM orders o JOIN customers c ON c.id=o.customer_id';$params=[];if($cid){$sql.=' WHERE o.customer_id=?';$params[]=$cid;}$sql.=' ORDER BY o.id DESC LIMIT 250';$s=vp3_db()->prepare($sql);$s->execute($params);$rows=$s->fetchAll();?><h1>Orders</h1><div class="table-wrap"><table class="table"><thead><tr><th>Order</th><th>Customer</th><th>Status</th><th>Payment</th><th>Total</th><th>Created</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['order_number'])?></td><td><?=vp3_e($x['customer_name'])?><br><small><?=vp3_e($x['email'])?></small></td><td><span class="badge <?=vp3_e($x['order_status'])?>"><?=vp3_e($x['order_status'])?></span></td><td><span class="badge <?=vp3_e($x['payment_status'])?>"><?=vp3_e($x['payment_status'])?></span></td><td><?=vp3_e(vp3_money((int)$x['total_cents'],$x['currency']))?></td><td><?=vp3_e($x['created_at'])?></td><td><a href="order.php?id=<?=(int)$x['id']?>">Open</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>